VALUES
  ('locality-c5fb3965-moex-00167', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '關於公務員懲戒法之適用範圍與對象，下列敘述何者錯誤？', '["非執行職務之違法行為，若嚴重損害政府之信譽亦應受懲戒", "公務員之行為非出於故意或過失者，不受懲戒", "適用對象包括政務人員", "不適用於退休或離職之公務員於任職期間之行為"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00168', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '關於行政規則之敘述，下列何者錯誤？', '["行政規則乃為上級機關對於下級機關所為規範機關內部秩序之抽象性規定", "行政規則對於法院並不具拘束力，法院有權直接宣告其無效", "上級機關為協助下級機關行使裁量權，得訂定裁量性行政規則", "有效下達之行政規則，具有拘束下級機關及屬官之效力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00169', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '關於法規命令之敘述，下列何者正確？', '["法規命令之內容應明列其法律授權之依據，不得逾越法律授權之範圍與立法精神，必要時，亦 可再委任下級機關訂定之", "行政機關訂定有關軍事、外交或其他重大事項且涉及國家機密或安全之法規命令，得不依行政 程序法所定程序為之", "行政機關擬訂法規命令時，得依職權採取各種適當方法，將公告內容廣泛周知", "法規命令依法應經上級機關核定者，應於發布後送上級機關核定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00170', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '依司法實務見解，下列何者非屬行政處分？', '["對公務員所為年終考績丙等之核定", "行政機關出借宿舍給所屬公務員", "對公務員作出記大過一次之懲處", "衛生福利部中央健康保險署對於其有全民健康保險特約之醫事服務機構所為之停止特約行為"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00171', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '依實務見解，行政程序法第98條第3項規定，自處分書送達後1年內聲明不服時，視為於法定 期間內所為之規定，對於下列何者不適用？', '["未受送達行政處分書之利害關係人", "行政處分相對人", "受送達行政處分書之利害關係人", "一般民眾"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00172', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '依行政程序法規定，下列何者非屬行政處分之無效事由？', '["具有重大明顯之瑕疵", "應以證書方式作成而未給予證書", "內容對任何人均屬不能實現", "違反有關土地管轄之規定 30830、31130 31930"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00173', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '下列何者得由行政機關與人民以行政契約辦理之？', '["公務員之免職", "國家考試是否錄取", "兵役機關徵召役男入伍", "稅捐機關依職權調查後，仍無法確定納稅義務人有無海外所得，而與人民簽訂和解契約"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00174', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '關於行政指導之敘述，下列何者錯誤？', '["行政指導乃不具法律上強制力之行為", "人民於必要時得請求以書面方式為之", "僅限於要求特定作為，不作為則非其對象", "行政指導在分類上可以歸納為事實行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00175', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '關於行政罰裁處之敘述，下列何者錯誤？', '["甲為乙利益而實施違反行政法上義務之行為，甲應受處罰，而乙受有財產上利益卻不須受處罰， 為裁處之主管機關得對乙所受財產上利益價值範圍內酌予追繳", "丙因違反行政法義務，行政機關依法得沒入其使用之物，但於行政機關沒入前，丙將該物毀壞 致無法沒入，行政機關得裁處沒入該物之價額", "丁為10歲之國民小學學童，下課後單獨搭乘大眾捷運，因飢餓難耐取出背包零食食用，主管機 關依違反大眾捷運法科處罰鍰", "戊平日均搭乘大眾捷運返家，其因心情欠佳，於飲酒後，在搭乘大眾捷運時，擅自開啟車門， 其雖已意識不清，仍可予以處罰"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL),
  ('locality-c5fb3965-moex-00176', 'locality-c5fb3965', 'locality-c5fb3965-moex-110-3082b5f1', 'sub-locality-c5fb3965-03', NULL, 'single_choice', '下列何者非屬直接強制方法？', '["封閉住宅", "拘提管收", "解除占有", "註銷證照"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:00+00:00", "source_pdf_sha1": "18fffff4b96c", "answer_pdf_sha1": "f164d0d22d36", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "303", "s": "0607", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "戶政"}'::jsonb, NULL)
